import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface YearlyGoal {
  targetBooks: number;
  booksRead: number;
  progressPercentage: number;
}

interface CurrentBook {
  title: string;
  author: string;
  currentPage: number;
  totalPages: number;
}

interface BooksReadThisYear {
  month: string;
  books: number;
}

interface ReadingData {
  yearlyGoal: YearlyGoal;
  currentBooks: CurrentBook[];
  booksReadThisYear: BooksReadThisYear[];
}

export default function Widget() {
  const readingData = response.data as ReadingData;
  const { yearlyGoal, currentBooks, booksReadThisYear } = readingData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FFC107' }}>
              Reading Goal
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {yearlyGoal.booksRead} / {yearlyGoal.targetBooks} Books
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Progress: {yearlyGoal.progressPercentage}%
            </Typography>
            <LinearProgress
              variant="determinate"
              value={yearlyGoal.progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#F3E8FF',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FFC107',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ color: '#3F51B5', mb: 1 }}>
              Current Books
            </Typography>
            <Stack spacing={1.5}>
              {currentBooks.map((book, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ color: '#1F2937' }}>
                    {book.title} by {book.author}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    Page {book.currentPage} of {book.totalPages}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <Typography variant="body2" fontWeight={600} sx={{ color: '#3F51B5', mb: 1 }}>
              Books Read This Year
            </Typography>
            <BarChart
              height={140}
              series={[
                {
                  data: booksReadThisYear.map(m => m.books),
                  color: '#3F51B5',
                },
              ]}
              xAxis={[
                {
                  data: booksReadThisYear.map(m => m.month),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
